void main() {
  group('AutoExploreSettingsSheet', () {
    testWidgets('shows resume affordance while auto-explore is yielded',
        (tester) async {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreSettingsSheet(),
            ),
          ),
        ),
      );

      expect(find.text('Auto-pilot paused (user correction)'), findsOneWidget);
      expect(find.text('Resume'), findsOneWidget);
      expect(find.text('Play'), findsNothing);
      expect(find.text('Pause'), findsNothing);
    });
  });

  group('AutoExploreButton semantics', () {
    testWidgets('exposes tap action for assistive activation', (tester) async {
      final semanticsHandle = tester.ensureSemantics();
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      final data = _semanticsDataForLabel(tester, 'Start auto-explore');
      expect(data, isNotNull);
      expect(data!.hasAction(SemanticsAction.tap), isTrue);
      // ignore: deprecated_member_use
      expect(data.hasFlag(SemanticsFlag.isButton), isTrue);

      semanticsHandle.dispose();
    });

    testWidgets('labels user-correction yield without claiming active motion',
        (tester) async {
      final semanticsHandle = tester.ensureSemantics();
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      final yieldedData = _semanticsDataForLabel(tester, 'Auto-pilot paused');
      final activeData = _semanticsDataForLabel(tester, 'Pause auto-explore');

      expect(yieldedData, isNotNull);
      expect(yieldedData!.hasAction(SemanticsAction.tap), isTrue);
      expect(activeData, isNull);

      semanticsHandle.dispose();
    });

    testWidgets('tap resumes from user-correction yield instead of pausing',
        (tester) async {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      await tester.tap(find.byType(AutoExploreButton));
      await tester.pump();

      expect(service.isExploring, isTrue);
      expect(service.isPaused, isFalse);
      expect(service.pausedByUserCorrection, isFalse);

      service.stop();
      await tester.pump();
    });
  });
}

SemanticsData? _semanticsDataForLabel(WidgetTester tester, String label) {
  // ignore: deprecated_member_use
  final root = tester.binding.pipelineOwner.semanticsOwner?.rootSemanticsNode;
  SemanticsData? result;

  bool visit(SemanticsNode node) {
    final data = node.getSemanticsData();
    if (data.label == label) {
      result = data;
      return false;
    }
    node.visitChildren(visit);
    return result == null;
  }

  if (root != null) visit(root);
  return result;
}

import 'dart:async';

import 'package:flutter_fractals/features/renderer/cpu/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu/cpu_tile_worker.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CpuTileWorker', () {
    test('propagates tile render failures instead of hanging', () async {
      final worker = await CpuTileWorker.spawn();
      addTearDown(worker.dispose);

      final future = worker.renderTile(_tileRequest(x0: 3, w: 2)).timeout(
            const Duration(seconds: 1),
            onTimeout: () => throw TimeoutException(
              'CpuTileWorker.renderTile did not reply to an invalid tile',
            ),
          );

      await expectLater(
        future,
        throwsA(
          isA<CpuTileWorkerException>().having(
            (error) => error.message,
            'message',
            contains('within the full viewport'),
          ),
        ),
      );
    });

    test('rejects jobs submitted after disposal instead of waiting forever',
        () async {
      final worker = await CpuTileWorker.spawn();
      worker.dispose();

      final future = worker.renderTile(_tileRequest()).timeout(
            const Duration(milliseconds: 200),
            onTimeout: () => throw TimeoutException(
              'CpuTileWorker.renderTile waited on a disposed worker',
            ),
          );

      await expectLater(future, _throwsDisposedWorkerStateError);
    });

    test('rejects pending jobs when disposal races an in-flight tile',
        () async {
      final worker = await CpuTileWorker.spawn();

      final future = worker.renderTile(_tileRequest()).timeout(
            const Duration(milliseconds: 200),
            onTimeout: () => throw TimeoutException(
              'CpuTileWorker.renderTile waited after disposal closed a job',
            ),
          );
      final expectation = expectLater(future, _throwsDisposedWorkerStateError);
      worker.dispose();

      await expectation;
    });
  });
}

Matcher get _throwsDisposedWorkerStateError => throwsA(
      isA<StateError>().having(
        (error) => error.message,
        'message',
        contains('disposed'),
      ),
    );

CpuTileRenderRequest _tileRequest({
  int fullWidth = 4,
  int fullHeight = 4,
  int x0 = 0,
  int y0 = 0,
  int w = 1,
  int h = 1,
}) {
  return CpuTileRenderRequest(
    moduleId: 'mandelbrot',
    panX: 0.0,
    panY: 0.0,
    zoom: 1.0,
    iterations: 32,
    bailout: 4.0,
    juliaCX: -0.8,
    juliaCY: 0.156,
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
    sampleCount: 1,
  );
}

